// SAFE: context-aware HTML encoding (Node.js/Express with escape-html)
const escapeHtml = require('escape-html');
app.get('/search', (req, res) => {
  const query = escapeHtml(req.query.q);
  res.send(`<p>You searched for: ${query}</p>`);
});

// SAFE: React auto-escaping (default behavior)
function SearchResults({ query }) {
  return <p>You searched for: {query}</p>;
  // React automatically escapes the query variable
}

